query GetAuditStatistics($fromDate: DateTime!, $toDate: DateTime!) {
  auditStatistics(fromDate: $fromDate, toDate: $toDate) {
    totalActions
    totalEntities
    topActions {
      action
      count
    }
    topEntities {
      entityType
      count
    }
